INSERT INTO public.products (slug, name, category, price_per_yard, short_description, description, delivery_notes, image_path, sort_order) VALUES
('black-mulch','Black Mulch','Mulch',75.00,'Premium dyed black mulch — bold contrast for gardens and beds.','Our Black Mulch is a beautifully dyed hardwood mulch that delivers a striking, rich, jet-black finish to flower beds and tree wells. It helps retain soil moisture, suppress weeds, and insulate plant roots through changing seasons. Coverage: 1 yard covers approximately 100 sq ft at 3" depth.','Available for delivery and pickup. Sold by the cubic yard.','black-mulch.jpg',10),
('cedar-mulch','Cedar Mulch','Mulch',55.00,'Naturally aromatic cedar mulch — repels insects and lasts.','Cedar Mulch is a natural, untreated wood mulch known for its distinct aroma and natural insect-repelling properties. It decomposes slowly, making it an economical, long-lasting choice for residential and commercial landscapes.','Available for delivery and pickup. Sold by the cubic yard.','cedar-mulch.jpg',20),
('crystal-white-rock','Crystal White Rock','Decorative Rock',390.00,'Premium bright white decorative rock for high-end landscapes.','Crystal White Rock is a luxurious, bright white decorative stone that adds a clean, elegant accent to any landscape. Ideal for water features, modern garden designs, and statement borders.','Premium product. Available for delivery and pickup. Sold by the cubic yard.','crystal-white-rock.jpg',30),
('garden-mix','Garden Mix 3-1-1','Soil',60.00,'Balanced blend of topsoil, peat and compost for healthy gardens.','Garden Mix 3-1-1 is a balanced blend of premium topsoil, peat moss, and compost. Perfect for new garden beds, vegetable gardens, and amending existing soil.','Available for delivery and pickup. Sold by the cubic yard.','garden-mix.jpg',40),
('limestone-20-30mm','Limestone 20-30mm','Limestone',144.00,'Medium crushed limestone — great for paths and drainage.','20-30mm crushed limestone is a versatile aggregate ideal for pathways, French drains, and decorative borders.','Available for delivery and pickup. Sold by the cubic yard.','limestone.jpg',50),
('limestone-25mm','Limestone 25mm','Limestone',132.00,'25mm crushed limestone for general landscaping use.','25mm crushed limestone is a workhorse aggregate suitable for base material, driveways, and pathways.','Available for delivery and pickup. Sold by the cubic yard.','limestone.jpg',60),
('limestone-30-65mm','Limestone 30-65mm','Limestone',144.00,'Larger crushed limestone for drainage and visual impact.','30-65mm limestone provides excellent drainage and a chunky, natural look perfect for dry creek beds and erosion control.','Available for delivery and pickup. Sold by the cubic yard.','limestone.jpg',70),
('limestone-75-100mm','Limestone 75-100mm','Limestone',148.00,'Large limestone for retaining edges and bold features.','Large 75-100mm limestone is ideal for retaining wall fill, riprap, and bold decorative use.','Available for delivery and pickup. Sold by the cubic yard.','limestone.jpg',80),
('limestone-dust-10-minus','Limestone Dust (10 Minus)','Limestone',124.00,'Fine limestone screening — perfect base for pavers.','Limestone Dust (10 Minus) compacts to a firm, level surface, making it the ideal base material for pavers, flagstone, and artificial turf.','Available for delivery and pickup. Sold by the cubic yard.','limestone.jpg',90),
('majestic-midnight-20mm','Majestic Midnight 20mm','Decorative Rock',165.00,'Sleek 20mm dark basalt — striking modern accent stone.','Majestic Midnight 20mm is a refined dark basalt rock that brings drama and sophistication to contemporary landscapes.','Available for delivery and pickup. Sold by the cubic yard.','majestic-midnight.jpg',100),
('majestic-midnight-30-65mm','Majestic Midnight 30-65mm','Decorative Rock',170.00,'Medium dark basalt — modern statement rock.','30-65mm Majestic Midnight is perfect for water features, modern garden borders, and dry creek beds.','Available for delivery and pickup. Sold by the cubic yard.','majestic-midnight.jpg',110),
('majestic-midnight-40mm','Majestic Midnight 40mm','Decorative Rock',168.00,'40mm dark basalt for bold, contemporary landscape designs.','Majestic Midnight 40mm offers a refined, uniform look ideal for high-impact modern landscapes.','Available for delivery and pickup. Sold by the cubic yard.','majestic-midnight.jpg',120),
('nugget-medium-bark-mulch','Nugget Medium Bark Mulch','Mulch',100.00,'Chunky natural bark mulch — long-lasting decorative cover.','Nugget Medium Bark Mulch features larger natural bark pieces that resist decomposition and provide great visual texture.','Available for delivery and pickup. Sold by the cubic yard.','nugget-bark.jpg',130),
('pine-mulch','Pine Mulch','Mulch',44.00,'Affordable natural pine mulch — value choice for large beds.','Pine Mulch is an economical, natural option for covering large areas. Lightweight and easy to spread.','Available for delivery and pickup. Sold by the cubic yard.','pine-mulch.jpg',140),
('play-sand','Play Sand','Sand & Gravel',90.00,'Clean, fine sand — safe for sandboxes and playgrounds.','Washed and screened play sand suitable for sandboxes, play areas, and decorative use. Free of sharp debris.','Available for delivery and pickup. Sold by the cubic yard.','play-sand.jpg',150),
